mapper.select:
SELECT COUNT(*)
FROM favorite_rental_notices
WHERE user_id = #{userId}
  AND notice_id = #{noticeId}

mapper.delete:
DELETE FROM favorite_rental_notices
WHERE user_id = #{userId}
  AND notice_id = #{noticeId}

mapper.select:
SELECT notice_id
FROM favorite_rental_notices
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}
